(window.webpackJsonp=window.webpackJsonp||[]).push([[688],{957:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for singly-linked list.\\n * function ListNode(val) {\\n *     this.val = val;\\n *     this.next = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{ListNode[]}</span> <span class=\\"hljs-variable\\">lists</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{ListNode}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> mergeKLists = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">lists</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(lists.length===<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">null</span>\\n  <span class=\\"hljs-keyword\\">while</span>(lists.length&gt;<span class=\\"hljs-number\\">1</span>){\\n    <span class=\\"hljs-keyword\\">let</span> len=<span class=\\"hljs-built_in\\">Math</span>.floor(lists.length/<span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;len;i++){\\n      <span class=\\"hljs-keyword\\">let</span> list1=lists.shift(),list2=lists.shift()\\n      lists.push(merge(list1,list2))\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> lists[<span class=\\"hljs-number\\">0</span>]\\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">merge</span>(<span class=\\"hljs-params\\">list1,list2</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> root=<span class=\\"hljs-keyword\\">new</span> ListNode(<span class=\\"hljs-literal\\">null</span>)\\n    <span class=\\"hljs-keyword\\">let</span> res=root\\n    <span class=\\"hljs-keyword\\">let</span> node1=list1,node2=list2\\n    <span class=\\"hljs-keyword\\">while</span>(node1 || node2){\\n      <span class=\\"hljs-keyword\\">if</span>(!node1){\\n        res.next=node2\\n        node2=node2.next\\n      }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(!node2){\\n        res.next=node1\\n        node1=node1.next\\n      }<span class=\\"hljs-keyword\\">else</span>{\\n        <span class=\\"hljs-keyword\\">if</span>(node1.val&gt;node2.val){\\n          res.next=node2\\n          node2=node2.next\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n          res.next=node1\\n          node1=node1.next\\n        }\\n      }\\n      res=res.next\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> root.next\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"merge-k-sorted-lists","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u597d\u51e0\u79cd\u65b9\u6cd5\u80fd\u89e3\u51b3\uff0c</p>\\n<ol>\\n<li>\\n<p>\u76f4\u63a5\u6392\u5e8f\uff0c\u5c06\u6bcf\u4e00\u4e2a<code>node.val</code>\u6dfb\u52a0\u5230\u6570\u7ec4\uff0c\u7136\u540e\u6392\u5e8f\u540e\u91cd\u65b0\u751f\u6210\u94fe\u8868\u3002</p>\\n</li>\\n<li>\\n<p>\u4f18\u5148\u961f\u5217\uff0c\u5c06\u6bcf\u4e00\u4e2a<code>node</code>\u52a0\u5165<code>Priority Queue</code>\uff0c\u7136\u540e\u518d\u4ece\u5c0f\u5230\u5927\u5bfc\u51fa\u5373\u53ef\u3002</p>\\n</li>\\n<li>\\n<p>\u5f52\u5e76\u6392\u5e8f(\u89c1\u4ee3\u7801)\u3002</p>\\n</li>\\n<li>\\n<p>\u591a\u6307\u9488(\u6bd4\u8f83\u6162)\uff0c\u6bcf\u4e00\u6b21\u90fd\u627e\u51fa\u5f53\u524d\u6bcf\u4e00\u4e2a<code>list[i]</code>\u4e2d\u7684\u6700\u5c0f\u503c\uff0c\u627e\u5230\u7684\u90a3\u4e2a\u8282\u70b9\u6267\u884c<code>list[i]=list[i].next</code>\u3002</p>\\n</li>\\n</ol>\\n","content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u94fe\u8868\u6570\u7ec4\uff0c\u6bcf\u4e2a\u94fe\u8868\u90fd\u5df2\u7ecf\u6309\u5347\u5e8f\u6392\u5217\u3002</p>\\n\\n<p>\u8bf7\u4f60\u5c06\u6240\u6709\u94fe\u8868\u5408\u5e76\u5230\u4e00\u4e2a\u5347\u5e8f\u94fe\u8868\u4e2d\uff0c\u8fd4\u56de\u5408\u5e76\u540e\u7684\u94fe\u8868\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>lists = [[1,4,5],[1,3,4],[2,6]]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,1,2,3,4,4,5,6]\\n<strong>\u89e3\u91ca\uff1a</strong>\u94fe\u8868\u6570\u7ec4\u5982\u4e0b\uff1a\\n[\\n  1-&gt;4-&gt;5,\\n  1-&gt;3-&gt;4,\\n  2-&gt;6\\n]\\n\u5c06\u5b83\u4eec\u5408\u5e76\u5230\u4e00\u4e2a\u6709\u5e8f\u94fe\u8868\u4e2d\u5f97\u5230\u3002\\n1-&gt;1-&gt;2-&gt;3-&gt;4-&gt;4-&gt;5-&gt;6\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>lists = []\\n<strong>\u8f93\u51fa\uff1a</strong>[]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>lists = [[]]\\n<strong>\u8f93\u51fa\uff1a</strong>[]\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>k == lists.length</code></li>\\n\\t<li><code>0 &lt;= k &lt;= 10^4</code></li>\\n\\t<li><code>0 &lt;= lists[i].length &lt;= 500</code></li>\\n\\t<li><code>-10^4 &lt;= lists[i][j] &lt;= 10^4</code></li>\\n\\t<li><code>lists[i]</code> \u6309 <strong>\u5347\u5e8f</strong> \u6392\u5217</li>\\n\\t<li><code>lists[i].length</code> \u7684\u603b\u548c\u4e0d\u8d85\u8fc7 <code>10^4</code></li>\\n</ul>\\n","title":"23. \u5408\u5e76K\u4e2a\u5347\u5e8f\u94fe\u8868","relatedTags":["\u5806","\u94fe\u8868","\u5206\u6cbb\u7b97\u6cd5"],"difficult":"Hard","lang":["javascript"],"uniqueID":"23"}')}}]);